document.addEventListener("DOMContentLoaded", function() {
    const banner = document.getElementById('cookie-banner');
    const allowButton = document.getElementById('cookie-allow');
    const denyButton = document.getElementById('cookie-deny');
    const resetButton = document.getElementById('cookie-reset');

    // Funcții globale pentru banner
    window.showBanner = function() {
        banner.style.display = 'flex';
        requestAnimationFrame(() = banner.classList.add('show'));
    }

    window.hideBanner = function() {
        banner.classList.remove('show');
        banner.classList.add('hide');
        setTimeout(() = {
            banner.style.display = 'none';
            banner.classList.remove('hide');
        }, 500);
    }

    // Funcții globale pentru buton reset
    window.showResetButton = function() {
        resetButton.style.display = 'flex';
        requestAnimationFrame(() = resetButton.classList.add('active'));
    }

    window.hideResetButton = function() {
        resetButton.classList.remove('active');
        setTimeout(() = {
            resetButton.style.display = 'none';
        }, 500);
    }

    // Funcții locale auxiliare (poți păstra dacă vrei)
    function showElement(el) {
        el.style.display = 'flex';
        requestAnimationFrame(() = el.classList.add('active'));
    }

    function hideElement(el) {
        el.classList.remove('active');
        setTimeout(() = {
            el.style.display = 'none';
        }, 500);
    }

    // Gestionarea consimțământului
    function handleConsent(choice) {
        localStorage.setItem('cookieConsent', choice);

        if (typeof gtag === 'function') {
            gtag('consent', 'update', {
                'ad_storage': choice === 'allow' ? 'granted' : 'denied',
                'analytics_storage': choice === 'allow' ? 'granted' : 'denied'
            });
        }

        window.hideBanner();
        window.showResetButton();
    }

    // Inițial: afișăm doar resetButton dacă există consimțământ
    if (localStorage.getItem('cookieConsent')) {
        window.showResetButton();
    }

    // Evenimente pentru butoane
    allowButton.addEventListener('click', () = handleConsent('allow'));
    denyButton.addEventListener('click', () = handleConsent('deny'));

    resetButton.addEventListener('click', () = {
        localStorage.removeItem('cookieConsent');
        window.hideResetButton();
        window.showBanner();
    });
});
